// Memory store (§4b: store ALL, never forget). Mock backing = localStorage on
// the device (also the privacy story for v1 — data stays local). The real seam
// is a database; the same add/all/delete interface holds.
import type { Memory } from "./types";

const KEY = "dm.memories";

function read(): Memory[] {
  try {
    const raw = localStorage.getItem(KEY);
    return raw ? (JSON.parse(raw) as Memory[]) : [];
  } catch {
    return [];
  }
}

function write(list: Memory[]): void {
  try {
    localStorage.setItem(KEY, JSON.stringify(list));
  } catch {
    /* storage full — real backend wouldn't have this limit */
  }
}

function uid(): string {
  if (typeof crypto !== "undefined" && crypto.randomUUID) return crypto.randomUUID();
  return "m-" + Math.random().toString(36).slice(2) + Date.now().toString(36);
}

/** All memories, newest visit first. */
export function allMemories(): Memory[] {
  return read().sort((a, b) => b.ts - a.ts);
}

export function addMemory(m: Omit<Memory, "id">): Memory {
  const full: Memory = { ...m, id: uid() };
  const list = read();
  list.push(full);
  write(list);
  return full;
}

export function addMemories(ms: Omit<Memory, "id">[]): Memory[] {
  const list = read();
  const added = ms.map((m) => ({ ...m, id: uid() }));
  list.push(...added);
  write(list);
  return added;
}

export function deleteMemory(id: string): void {
  write(read().filter((m) => m.id !== id));
}

/** User-initiated wipe (privacy: own + delete). */
export function deleteAllMemories(): void {
  write([]);
}

export function memoryCount(): number {
  return read().length;
}
