// Recall seam. The public demo has NO endpoint → always the mock (instant,
// no key, no spend). When Eugene builds with VITE_RECALL_ENDPOINT set (his own
// host, key in server env), the real Haiku 4.5 backend answers — but ONLY when
// the mock already found CONFIDENT memories, and grounded on those SAME cited
// memories (Clean Wall: we send just their text). Any failure/cap → the honest
// mock. This preserves §4b + 唔老作 no matter which path runs.

import type { Catalogue, Memory } from "./types";
import { answerRecall, type RecallResult } from "./recall";
import { ago } from "./dom";

const ENDPOINT = (import.meta.env.VITE_RECALL_ENDPOINT as string | undefined) || "";

export async function recall(
  query: string,
  memories: Memory[],
  cat: Catalogue
): Promise<RecallResult> {
  // Mock first: does §4b retrieval, applies 唔老作, and produces the citations.
  const base = answerRecall(query, memories, cat);

  // No backend, or nothing confident to ground on → honest mock, no call, no spend.
  if (!ENDPOINT || base.kind === "empty" || base.cited.length === 0) return base;

  try {
    // Clean Wall: send ONLY the query + the retrieved memory TEXT (≤10). No photos,
    // no ids, no device info.
    const payload = {
      query,
      memories: base.cited.slice(0, 10).map((c) => ({
        restaurantName: c.memory.restaurantName,
        area: c.memory.area,
        ago: ago(c.memory.ts),
        dishes: c.memory.dishes.map((d) => d.name),
      })),
    };
    const res = await fetch(ENDPOINT, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify(payload),
    });
    if (!res.ok) return base;
    const data = (await res.json()) as { grounded?: boolean; text?: string };
    if (data?.grounded && typeof data.text === "string" && data.text.trim()) {
      // Keep the mock's citations + kind; swap in the LLM's grounded wording.
      return { ...base, text: data.text.trim() };
    }
    return base; // capped / not grounded → honest mock
  } catch {
    return base; // network error → honest mock
  }
}
