// FEHD catalogue: load + search. The "基本盤" — a complete HK restaurant list.
import type { Catalogue, Restaurant } from "./types";

let cache: Catalogue | null = null;

export async function loadCatalogue(baseUrl: string): Promise<Catalogue> {
  if (cache) return cache;
  const res = await fetch(`${baseUrl}data/restaurants.json`);
  if (!res.ok) throw new Error(`catalogue load failed: ${res.status}`);
  cache = (await res.json()) as Catalogue;
  return cache;
}

function norm(s: string): string {
  return (s || "").toLowerCase().replace(/[\s'()（）.,·&-]/g, "");
}

